DROP TABLE WC_TEMP_SNAP_DS;

CREATE TABLE WC_TEMP_SNAP_DS AS
((select max(to_char(trunc(load_dt),'yyyymmdd')) as dates from w_etl_run_s)
union
(select distinct to_char(to_date(M_END_CAL_DT_WID,'yyyymmdd'),'yyyymmdd')
from w_day_d where calendar_date between add_months(to_date(to_char((select max(load_dt) from w_etl_run_s),'yyyymmdd'),'yyyymmdd'),-11)
and add_months(to_date(to_char((select max(load_dt) from w_etl_run_s),'yyyymmdd'),'yyyymmdd'),-1)));

TRUNCATE TABLE WC_EMP_HEAD_COUNT_DS;

COMMIT;

BEGIN 
WC_TERM_SNAP_PROC_DS\;
END\;
